import { 菩薩坐身, 上臂常勢, 前臂 } from './pusa.js';
import { 塗香器 } from '../bujian/sanmaya.js';
import { 運筆 } from '../bi.js';
import { 畫指 } from '../bujian/zhi.js';
import { 側拳, 臂釧, 腕釧 } from '../bujian/index.js';
export const 金剛塗 = (bi) => 菩薩坐身(bi, {
    髻: '天髻',
    冠: '無',
    嚴先: true,
    臂(bi, 筆) {
        const { M, Qk, S, 骨, 衣, 細, 陰, 陽 } = 筆;
        骨(() => { 上臂常勢(筆, -1, 40.0); 上臂常勢(筆, 1, 40.2); });
        // 尊左：托塗香器（器先落，掌承其下）
        塗香器(bi, 4.6, 36.6, 0.85);
        骨(() => 陰(() => 前臂(bi, 筆, [13.8, 40.3], [7.6, 39.6], { 寬根: 2.5, 寬梢: 1.9, 弓: -0.35, 肘帽: true })));
        衣(() => {
            M(6.9, 38.6);
            Qk(5.2, 39.4, 3.4, 38.8);
            S();
            M(6.6, 39.3);
            Qk(5.2, 40.0, 3.8, 39.4);
            S();
        });
        // 尊右：拳而獨伸小指，入器之上（指先落，拳覆其根）
        骨(() => 陽(() => 前臂(bi, 筆, [-13.7, 40.1], [-5.7, 37.4], { 寬根: 2.5, 寬梢: 1.9, 弓: 0.4, 肘帽: true })));
        {
            const 運 = 運筆(bi);
            運.衣(() => {
                畫指(運, [[-2.9, 36.2], [-0.9, 35.8], [0.9, 35.9], [2.2, 36.2]], 0.85, 0.6, { 紋: true }, bi);
            });
        }
        側拳(bi, -4.0, 36.3, 0.4, 1.1);
        // 嚴
        臂釧(bi, -1, 12.1, 14.5, 33.4);
        臂釧(bi, 1, 12.1, 14.5, 33.4);
        細(() => {
            腕釧(bi, [[-7.0, 36.6, -6.3, 37.5, -7.0, 38.6], [-6.1, 36.4, -5.4, 37.3, -6.1, 38.4]], [-6.3, 37.5]);
            腕釧(bi, [[8.7, 38.2, 8.2, 39.3, 8.7, 40.5], [9.6, 38.4, 9.1, 39.5, 9.6, 40.7]], [9.3, 39.5]);
        });
    },
});
